__kernel void dynproc_kernel(
    int pyramid_height,
    __global int* gpuWall,
    __global int* gpuResult_src,
    __global int* gpuResult_dst,
    int cols,
    int rows,
    int t_start,
    int borderCols,
    int theHalo,
    __local int* local_mem1,
    __local int* local_mem2,
    __global int* outputBuffer)
{
    int n = get_global_id(0);

    if (n >= cols) return;

    for (int h = 0; h < pyramid_height; h++) {
        int current_row = t_start + h;
        if (current_row >= rows - 1) break;

        int min = gpuResult_src[n];
        if (n > 0) {
            int left = gpuResult_src[n-1];
            min = (min <= left) ? min : left;
        }
        if (n < cols-1) {
            int right = gpuResult_src[n+1];
            min = (min <= right) ? min : right;
        }

        gpuResult_dst[n] = gpuWall[current_row * cols + n] + min;
    }
}
